import * as authService from "../services/authService";
import * as userService from "../services/userService";
import * as productService from "../services/productService";
import * as categoryService from "../services/categoryService";
import * as supplierService from "../services/supplierService";
import * as warehouseService from "../services/warehouseService";
import * as taskService from "../services/taskService";
import * as inventoryService from "../services/inventoryService";
import * as purchaseRequestService from "../services/purchaseRequestService";
import * as purchaseOrderService from "../services/purchaseOrderService";
import * as salesOrderService from "../services/salesOrderService";
import * as stockService from "../services/stockService";
import * as activityLogService from "../services/activityLogService";
import * as transactionAdapter from "../services/transactionAdapter";
import {
  clearAuth,
  getAuthSession,
  getExpirationTime,
  getRole,
  getToken,
  getUserId,
  isAdmin,
  isAuthenticated,
  saveAuthSession,
  saveRole,
  saveToken,
} from "../services/apiClient";

const ApiService = {
  ...authService,
  ...userService,
  ...productService,
  ...categoryService,
  ...supplierService,
  ...warehouseService,
  ...taskService,
  ...inventoryService,
  ...purchaseRequestService,
  ...purchaseOrderService,
  ...salesOrderService,
  ...stockService,
  ...activityLogService,
  ...transactionAdapter,
  saveAuthSession,
  saveToken,
  getToken,
  saveRole,
  getRole,
  getUserId,
  getExpirationTime,
  getAuthSession,
  clearAuth,
  isAuthenticated,
  isAdmin,
  logout() {
    clearAuth();
  },
  getLoggedInUserInfo() {
    return userService.getLoggedInUserInfo();
  },
  getLoggedInUsesInfo() {
    return userService.getLoggedInUserInfo();
  },
};

export default ApiService;
